{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"],
    "confirmed_decisions": [
      {
        "decision": "스모크 테스트가 통과하면 공개 릴리스 목표 시점은 금요일 15:00 KST로 한다.",
        "conditions": ["스모크 테스트 통과"],
        "source_certainty": "confirmed"
      },
      {
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인한다.",
        "conditions": ["packageName mismatch 발생 시"],
        "source_certainty": "confirmed"
      },
      {
        "decision": "스크립트는 계약 자체가 잘못된 경우에만 검토한다.",
        "conditions": ["패키지 계약 자체가 잘못된 것으로 확인된 경우"],
        "source_certainty": "confirmed"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs가 packageName mismatch를 무시하도록 변경한다.",
        "proposed_by": "Hara",
        "outcome": "rejected",
        "source_certainty": "confirmed"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "proposed_by": "Seoyeon",
        "status": "internal_stretch_goal_only",
        "reason": "Doyun이 스모크 테스트 통과가 먼저 필요하다고 이의 제기함",
        "source_certainty": "confirmed"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 단계는 목요일까지 가능하면 검토해야 한다는 의견이 있었지만 담당자는 지정되지 않았다.",
        "source_certainty": "confirmed"
      },
      {
        "item": "Hara의 생성된 tarball 경로 확인에는 정확한 마감 시점이 정해지지 않았다.",
        "source_certainty": "confirmed"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로가 릴리스를 지연시킬 수 있다.",
        "source_certainty": "confirmed"
      },
      {
        "risk": "README 설치 단계가 오래된 경우 릴리스 노트가 사용자를 오도할 수 있다.",
        "source_certainty": "confirmed"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?",
        "source_certainty": "confirmed"
      },
      {
        "question": "릴리스 노트에 내부 수요일 stretch goal을 언급해야 하는가?",
        "source_certainty": "confirmed"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 triage note를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 후 생성된 tarball 경로를 확인한다.",
      "due": null,
      "status": "confirmed_no_exact_deadline",
      "source_certainty": "confirmed"
    },
    {
      "owner": null,
      "task": "README 설치 단계를 목요일까지 가능하면 검토한다.",
      "due": "목요일 if possible",
      "status": "suggested_no_owner_assigned",
      "source_certainty": "confirmed"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 금요일 10:00 KST 스모크 테스트 재실행 결과를 확인한다.",
      "Doyun의 금요일 12:00 KST action_items.md 실패 triage note 작성 여부를 확인한다.",
      "스모크 결과 게시 후 Hara가 생성된 tarball 경로를 확인했는지 확인한다.",
      "README 설치 단계 검토 담당자를 지정할지 확인한다.",
      "최종 릴리스 승인 권한자를 확인한다.",
      "릴리스 노트에 내부 수요일 stretch goal을 언급할지 결정한다."
    ],
    "do_not_invent": [
      "고객명",
      "외부 파트너",
      "예산",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요건",
      "명시되지 않은 담당자",
      "명시되지 않은 마감일"
    ]
  },
  "non_invention_rules": {
    "customer": "고객 또는 외부 파트너는 언급되지 않았으므로 만들지 않는다.",
    "budget": "예산 정보는 언급되지 않았으므로 만들지 않는다.",
    "security": "보안 사고는 언급되지 않았으므로 만들지 않는다.",
    "outage": "프로덕션 장애는 언급되지 않았으므로 만들지 않는다.",
    "legal": "법무 승인 요건은 언급되지 않았으므로 만들지 않는다.",
    "owners": "담당자가 지정되지 않은 항목에는 owner를 null로 둔다.",
    "deadlines": "정확한 마감이 없는 항목에는 due를 null 또는 원문 조건부 표현으로 둔다.",
    "golden_reference": "참조 출력이나 golden output은 사용하지 않는다."
  }
}
